Source code in <code>compiled_memory.py</code> <pre><code>def load_compiled_facts(path: Path | None = None) -&gt; list[CompiledFact]:
    path = path or DEFAULT_OUT_DIR / FACTS_JSONL
    if not path.exists():
        return []
    facts: list[CompiledFact] = []
    for line in path.read_text(encoding="utf-8").splitlines():
        if not line.strip():
            continue
        try:
            facts.append(CompiledFact.from_record(json.loads(line)))
        except (TypeError, ValueError, json.JSONDecodeError):
            continue
    return facts
